body:
## 🐛 Bug description

We are using a lerna monorepo with two remix apps and a component library bundled with rollup, there is a brief moment while the page is loading where the hits and categories have not loaded.

this does not occur when the component is built entirely inside the remix apps, I'm not fully sure what is causing it, but there is a delay between the categories/hits loading and rest of the component, only when loaded from our component library.

the instant search component is built like this:  
```
import type { Hit as AlgoliaHit } from 'instantsearch.js';
import algoliasearch from 'algoliasearch';
import type { FC } from 'react';
import React from 'react';
import {
    InstantSearch,
    Breadcrumb,
    Configure,
    ClearRefinements,
    CurrentRefinements,
    HierarchicalMenu,
    Highlight,
    Hits,
    HitsPerPage,
    InfiniteHits,
    Menu,
    Pagination,
    RangeInput,
    RefinementList,
    PoweredBy,
    SearchBox,
    SortBy,
    ToggleRefinement
} from 'react-instantsearch-hooks-web';

import { Panel } from './Panel/Panel';
import { Tab, Tabs } from './Tabs/Tabs';
import { QueryRuleContext } from './QueryRule/QueryRuleContext';
import { QueryRuleCustomData } from './QueryRule/QueryRuleCustomData';
import { Refresh } from './Refresh/Refresh';

// const searchClient = algoliasearch('CMEG2XKNP8', '45b007891e2e306b97a88d7da87afac8');
// const searchClient = algoliasearch(process.env.ALGOLIA_ID, process.env.ALGOLIA_ID_SEARCH_ONLY);

type HitProps = {
    hit: AlgoliaHit<{
        title: string;
        price: number;
    }>;
};

function Hit({ hit }: HitProps) {
    return (
        <>
            <Highlight hit={hit} attribute="title" className="Hit-label" />
            <span className="Hit-price">${hit.price}</span>
        </>
    );
}

interface InstantSearchProps {
    routingObject: {};
    ALGOLIA_ID: string;
    ALGOLIA_ID_SEARCH_ONLY: string;
}
export const OscInstantSearch: FC<InstantSearchProps> = (props) => {
    const searchClient = algoliasearch(props.ALGOLIA_ID, props.ALGOLIA_ID_SEARCH_ONLY);

    return (
        <InstantSearch
            searchClient={searchClient}
            indexName="shopify_products"
            routing={props.routingObject}
        >
            <Configure ruleContexts={[]} />

            <div className="Container">
                <div>
                    {/* <DynamicWidgets> */}
                    <Panel header="option names">
                        <RefinementList
                            attribute="option_names"
                            searchable={true}
                            searchablePlaceholder="Search options"
                            showMore={true}
                        />
                    </Panel>
                    <Panel header="tags">
                        <RefinementList
                            attribute="tags"
                            searchable={true}
                            searchablePlaceholder="Search tags"
                            showMore={true}
                        />
                    </Panel>
                    <Panel header="price_range">
                        <RefinementList
                            attribute="price_range"
                            searchable={true}
                            searchablePlaceholder="Search price range"
                            showMore={true}
                        />
                    </Panel>
                    <Panel header="options.format">
                        <Menu attribute="options.format" showMore={true} />
                    </Panel>
                    <Panel header="Hierarchy">
                        <HierarchicalMenu
                            attributes={[
                                'hierarchicalCategories.lvl0',
                                'hierarchicalCategories.lvl1',
                                'hierarchicalCategories.lvl2'
                            ]}
                            showMore={true}
                        />
                    </Panel>
                    <Panel header="Price">
                        <RangeInput attribute="price" />
                    </Panel>
                    <Panel header="Free Shipping">
                        <ToggleRefinement attribute="free_shipping" label="Free shipping" />
                    </Panel>
                    {/* </DynamicWidgets> */}
                </div>
                <div className="Search">
                    <Breadcrumb
                        attributes={[
                            'hierarchicalCategories.lvl0',
                            'hierarchicalCategories.lvl1',
                            'hierarchicalCategories.lvl2'
                        ]}
                    />

                    <SearchBox placeholder="Search" />

                    <div className="Search-header">
                        <PoweredBy />
                        <HitsPerPage
                            items={[
                                { label: '20 hits per page', value: 20, default: true },
                                { label: '40 hits per page', value: 40 }
                            ]}
                        />
                        <SortBy
                            items={[
                                {
                                    label: 'Relevance',
                                    value: 'shopify_products'
                                },
                                {
                                    label: 'Price (asc)',
                                    value: 'shopify_products_recently_ordered_count_desc_price_asc'
                                },
                                {
                                    label: 'Price (desc)',
                                    value: 'shopify_products_recently_ordered_count_desc_price_desc'
                                }
                            ]}
                        />
                        <Refresh />
                    </div>

                    <div className="CurrentRefinements">
                        <CurrentRefinements
                            transformItems={(items) =>
                                items.map((item) => {
                                    const label = item.label.startsWith('hierarchicalCategories')
                                        ? 'Hierarchy'
                                        : item.label;

                                    return {
                                        ...item,
                                        attribute: label
                                    };
                                })
                            }
                        />
                        <ClearRefinements />
                    </div>

                    <QueryRuleContext
                        trackedFilters={{
                            brand: () => ['Apple']
                        }}
                    />

                    <QueryRuleCustomData>
                        {({ items }) => (
                            <>
                                {items.map((item) => {
                                    console.log(item);
                                    return (
                                        <a href={item.link} key={item.banner}>
                                            <img src={item.banner} alt={item.title} />
                                        </a>
                                    );
                                })}
                            </>
                        )}
                    </QueryRuleCustomData>

                    <Tabs>
                        <Tab title="Hits">
                            <Hits hitComponent={Hit} />
                            <Pagination className="Pagination" />
                        </Tab>
                        <Tab title="InfiniteHits">
                            <InfiniteHits showPrevious hitComponent={Hit} />
                        </Tab>
                    </Tabs>
                </div>
            </div>
        </InstantSearch>
    );
};
```
the component is imported into the remix packages like this:

```import React from 'react';
import { useLocation, useMatches } from '@remix-run/react';
import type { HeadersFunction } from '@remix-run/node';
import { useLoaderData } from '@remix-run/react';
import { getColorScheme } from './cookie';
import lightTheme from './theme/lightTheme';
import darkTheme from './theme/darkTheme';
import type { LinksFunction, LoaderFunction, MetaFunction } from '@remix-run/node';
import { json } from '@remix-run/node';
import { LiveReload, Meta, Outlet, Scripts, ScrollRestoration } from '@remix-run/react';
import { ChakraProvider } from '@chakra-ui/react';
import { withEmotionCache } from '@emotion/react';
import { Header } from 'osc-ui';
import { OscInstantSearch as InstantSearch } from './components/InstantSearch/InstantSearch';
import styles from './styles/dest/main.css';
import appHeaderStyles from './components/header.css';
import oscUiHeaderStyles from 'osc-ui/dist/1/header.css';
import oscUiInstantSearchRefreshStyles from 'osc-ui/dist/2/refresh.css';
import oscUiInstantSearchTabsStyles from 'osc-ui/dist/3/tabs.css';
import instantSearch from 'instantsearch.css/themes/satellite.css';
import { getUser } from './session.server';
import { useContext, useEffect } from 'react';
import { ClientStyleContext, ServerStyleContext } from './context';
import { checkConnectivity } from '~/utils/client/pwa-utils.client';
import { InstantSearchSSRProvider } from 'react-instantsearch-hooks-web';
import { getServerState } from 'react-instantsearch-hooks-server';
import { history } from 'instantsearch.js/es/lib/routers';
import path from 'path';
const fs = require('fs');
// import { PushNotification } from '~/utils/server/pwa-utils.server';

let isMount = true;

export const links: LinksFunction = () => {
    return [
        { rel: 'stylesheet', href: oscUiInstantSearchRefreshStyles },
        { rel: 'stylesheet', href: oscUiInstantSearchTabsStyles },
        { rel: 'stylesheet', href: oscUiHeaderStyles },
        { rel: 'stylesheet', href: styles },
        { rel: 'stylesheet', href: instantSearch },
        { rel: 'stylesheet', href: appHeaderStyles },
        { rel: 'manifest', href: '/resources/manifest.webmanifest' },
        { rel: 'apple-touch-icon', sizes: '57x57', href: '/icons/apple-icon-57x57.png' },
        { rel: 'apple-touch-icon', sizes: '60x60', href: '/icons/apple-icon-60x60.png' },
        { rel: 'apple-touch-icon', sizes: '72x72', href: '/icons/apple-icon-72x72.png' },
        { rel: 'apple-touch-icon', sizes: '76x76', href: '/icons/apple-icon-76x76.png' },
        { rel: 'apple-touch-icon', sizes: '114x114', href: '/icons/apple-icon-114x114.png' },
        { rel: 'apple-touch-icon', sizes: '120x120', href: '/icons/apple-icon-120x120.png' },
        { rel: 'apple-touch-icon', sizes: '144x144', href: '/icons/apple-icon-144x144.png' },
        { rel: 'apple-touch-icon', sizes: '152x152', href: '/icons/apple-icon-152x152.png' },
        { rel: 'apple-touch-icon', sizes: '180x180', href: '/icons/apple-icon-180x180.png' },
        {
            rel: 'icon',
            type: 'image/png',
            sizes: '192x192',
            href: '/icons/android-icon-192x192.png'
        },
        { rel: 'icon', type: 'image/png', sizes: '32x32', href: '/icons/favicon-32x32.png' },
        { rel: 'icon', type: 'image/png', sizes: '96x96', href: '/icons/favicon-96x96.png' },
        { rel: 'icon', type: 'image/png', sizes: '16x16', href: '/icons/favicon-16x16.png' }
    ];
};

export const meta: MetaFunction = () => ({
    charset: 'utf-8',
    title: 'OSC Academic Hub',
    viewport: 'width=device-width,initial-scale=1'
});

type LoaderData = {
    user: Awaited<ReturnType<typeof getUser>>;
    colorScheme: string;
    ALGOLIA_ID: string;
    ALGOLIA_ID_SEARCH_ONLY: string;
    serverState: any;
    url: string;
};

export const headers: HeadersFunction = () => ({
    'Accept-CH': 'Sec-CH-Prefers-Color-Scheme'
});

export const loader: LoaderFunction = async ({ request }) => {
    // await PushNotification(
    //     {
    //         title: 'Remix PWA',
    //         body: 'A server generated text body.'
    //     },
    //     1
    // );

    const serverState = await getServerState(
        <Search
            ALGOLIA_ID_SEARCH_ONLY={process.env.ALGOLIA_ID_SEARCH_ONLY}
            ALGOLIA_ID={process.env.ALGOLIA_ID}
            url={request.url}
        ></Search>
    );

    return json<LoaderData>({
        user: await getUser(request),
        colorScheme: await getColorScheme(request),
        ALGOLIA_ID: process.env.ALGOLIA_ID!,
        ALGOLIA_ID_SEARCH_ONLY: process.env.ALGOLIA_ID_SEARCH_ONLY!,
        serverState,
        url: request.url
    });
};

interface DocumentProps {
    children: React.ReactNode;
}

const Document = withEmotionCache(({ children }: DocumentProps, emotionCache) => {
    const serverStyleData = useContext(ServerStyleContext);
    const clientStyleData = useContext(ClientStyleContext);

    // Only executed on client
    useEffect(() => {
        // re-link sheet container
        emotionCache.sheet.container = document.head;
        // re-inject tags
        const tags = emotionCache.sheet.tags;
        emotionCache.sheet.flush();
        tags.forEach((tag) => {
            (emotionCache.sheet as any)._insertTag(tag);
        });
        // // reset cache to reapply global styles
        // clientStyleData?.reset();
    }, [clientStyleData, emotionCache.sheet]);

    const injectStyle = () => {
        let mainCss = '';

        const charkaStyles =
            serverStyleData?.map(({ key, ids, css }) => {
                mainCss = css;
                return (
                    <style
                        key={`css ${ids.join(' ')}`}
                        data-emotion={`css ${ids.join(' ')}`}
                        className={`${key}`}
                    >
                        {mainCss}
                    </style>
                );
            }) ?? [];

        const scssStyles = links().map((link, index) => {
            if (fs.existsSync(path.join(process.cwd(), link.href))) {
                console.log(link);

                mainCss = fs.readFileSync(path.join(process.cwd(), link.href)).toString();
                const fileName = link.href.substr(link.href.lastIndexOf('/') + 1, link.href.length);
                return (
                    <style
                        data-emotion={`css ${fileName}`}
                        key={`main-css ${index}`}
                        className={`${fileName}`}
                    >
                        {mainCss}
                    </style>
                );
            }
        });

        return [...charkaStyles, ...scssStyles];
    };

    return (
        <html lang="en">
            <head>
                {typeof document === 'undefined' && injectStyle()}
                {typeof document === 'undefined' && <Meta />}
                {/* <style id="insertionPoint"></style> */}
                {/* {typeof document === 'undefined' && <Links />} */}
            </head>
            <body>
                {children}
                <ScrollRestoration />
                <Scripts />
                <LiveReload />
            </body>
        </html>
    );
});
export default function App() {
    const { colorScheme, ALGOLIA_ID, ALGOLIA_ID_SEARCH_ONLY, serverState, url } = useLoaderData();
    let location = useLocation();
    let matches = useMatches();

    const online = () => {
        //..Do something for online state
    };

    const offline = () => {
        //..Do something for offline state
    };

    useEffect(() => {
        // The `console.log` method returns an object with a status of "success" if online and a pass message or a status of "bad" and a fail message if offline
        checkConnectivity(online, offline).then((data) => console.log(data));
    }, []);

    React.useEffect(() => {
        let mounted = isMount;
        isMount = false;
        if ('serviceWorker' in navigator) {
            if (navigator.serviceWorker.controller) {
                navigator.serviceWorker.controller?.postMessage({
                    type: 'REMIX_NAVIGATION',
                    isMount: mounted,
                    location,
                    matches,
                    manifest: window.__remixManifest
                });
            } else {
                let listener = async () => {
                    await navigator.serviceWorker.ready;
                    navigator.serviceWorker.controller?.postMessage({
                        type: 'REMIX_NAVIGATION',
                        isMount: mounted,
                        location,
                        matches,
                        manifest: window.__remixManifest
                    });
                };
                navigator.serviceWorker.addEventListener('controllerchange', listener);
                return () => {
                    navigator.serviceWorker.removeEventListener('controllerchange', listener);
                };
            }
        }
    }, [location, matches]);

    return (
        <Document>
            <ChakraProvider theme={colorScheme === 'light' ? lightTheme : darkTheme}>
                <h1> OSC ECOMMERCE test</h1>
                <Header
                    tester={'this works'}
                    className={'o-header--full'}
                    backgroundColor={'secondary'}
                />
                <Search
                    serverState={serverState}
                    ALGOLIA_ID_SEARCH_ONLY={ALGOLIA_ID_SEARCH_ONLY}
                    ALGOLIA_ID={ALGOLIA_ID}
                    url={url}
                ></Search>
                <Outlet />
            </ChakraProvider>
        </Document>
    );
}

interface SearchProps {
    serverState?: any;
    ALGOLIA_ID_SEARCH_ONLY: any;
    ALGOLIA_ID: any;
    url: any;
}

const Search = ({ serverState, ALGOLIA_ID_SEARCH_ONLY, ALGOLIA_ID, url }: SearchProps) => {
    return (
        <InstantSearchSSRProvider {...serverState}>
            <InstantSearch
                routingObject={
                    {
                        router: history({
                            getLocation: () => {
                                return typeof document === 'undefined'
                                    ? (new URL(url) as unknown as Location)
                                    : window.location;
                            }
                        })
                    } as any
                }
                ALGOLIA_ID_SEARCH_ONLY={ALGOLIA_ID_SEARCH_ONLY}
                ALGOLIA_ID={ALGOLIA_ID}
            ></InstantSearch>
        </InstantSearchSSRProvider>
    );
};

```
our design was heavily inspired by: https://www.algolia.com/doc/guides/building-search-ui/going-further/server-side-rendering/react-hooks/#with-remix

